Rule.Source:
  import sailpoint.object.Link;
  import sailpoint.object.Identity;
  import sailpoint.tools.Util;
  import java.text.SimpleDateFormat;

  boolean iiqDisabled = false;
  if(link.getAttribute("IIQDisabled")!=null){
    if(link.getAttribute("IIQDisabled") instanceof String)
      iiqDisabled = Boolean.valueOf(link.getAttribute("IIQDisabled"));
    else
      iiqDisabled = link.getAttribute("IIQDisabled");
  }
  //if account is disabled not dormant account
  if(iiqDisabled)
    return false;

  //Checking for fuuture expiration account
  String accountExp = link.getAttribute("accountExpires");
  boolean isAccountActive = false;
  if(Util.isNotNullOrEmpty(accountExp)){
    if( accountExp.equalsIgnoreCase("never") || accountExp.equalsIgnoreCase("0") || accountExp.equalsIgnoreCase("9223372036854775807"))
      isAccountActive = true;
    else{
      Date accountExpiryDate = new SimpleDateFormat("MM/dd/yyyy hh:mm:ss a z", Locale.ENGLISH).parse(accountExp);
      int daysDifference = Util.getDaysDifference(accountExpiryDate, new Date());
      if(daysDifference>-2)
        isAccountActive = true;
    }
  } else{
    isAccountActive = true;
  }

  //Account is inactive but not in a disabled state, so mark as dormant
  if(!isAccountActive)
    return true;
  
  Identity identity = link.getIdentity();
  String userType = "";
  if(null!=identity){
    	userType = identity.getType();
    if(identity.isInactive()){
    	return true;
    }
  }
    
  identity = null;
  
  String lastLogonTimestamp = link.getAttribute("lastLogonTimestamp");
  if(Util.isNotNullOrEmpty(lastLogonTimestamp)){
    Long DIFF_NET_JAVA_FOR_DATES = 11644473600000L;
    Long adLogon = (Long.parseLong(lastLogonTimestamp)/10000)-DIFF_NET_JAVA_FOR_DATES;
    int adLogonDifference =  Util.getDaysDifference(new Date(), new Date(adLogon));
    
    //its dormant account if not logged in 390 days ago for Employees/Physicians, 90 days for everyone else
    if(Util.isNotNullOrEmpty(userType) && (userType.equalsIgnoreCase("physician") || userType.equalsIgnoreCase("employee"))){
      if(adLogonDifference>390){
        return true;
      }
    } else{
        if(adLogonDifference>90){
        return true;
      }
    }
  } else{
      String whenCreatedTimestamp = link.getAttribute("whenCreated");
    if(Util.isNotNullOrEmpty(whenCreatedTimestamp)){
       Date adCreated = new SimpleDateFormat("yyyyMMddHHmmss", Locale.ENGLISH).parse(whenCreatedTimestamp);
      int adCreatedDifference =  Util.getDaysDifference(new Date(),adCreated);

      if(Util.isNotNullOrEmpty(userType) && (userType.equalsIgnoreCase("physician") || userType.equalsIgnoreCase("employee"))){
        if(adCreatedDifference>390){
          return true;
        }
      } else{
        if(adCreatedDifference>90){
          return true;
        }
      }
    }
  }

  return false;
